   roadmap:["5 phases + 5 tools","Nmap scan enum","Metasploit on vuln VM","web app manual enum","exploit SQLi/XSS/IDOR in lab","full lab pen test + report","eJPT/PNPT or 10 HTB","authorized real org test","OSCP"],
